// HasAccountLogin applies the HasEdge predicate on the "account_login" edge.
func HasAccountLogin() predicate.UserAccount {
	return predicate.UserAccount(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, true, AccountLoginTable, AccountLoginColumn),
		)
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.AccountLogin
		step.Edge.Schema = schemaConfig.UserAccount
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAccountLoginWith applies the HasEdge predicate on the "account_login" edge with a given conditions (other predicates).
func HasAccountLoginWith(preds ...predicate.AccountLogin) predicate.UserAccount {
	return predicate.UserAccount(func(s *sql.Selector) {
		step := newAccountLoginStep()
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.AccountLogin
		step.Edge.Schema = schemaConfig.UserAccount
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UserAccount) predicate.UserAccount {
	return predicate.UserAccount(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UserAccount) predicate.UserAccount {
	return predicate.UserAccount(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UserAccount) predicate.UserAccount {
	return predicate.UserAccount(sql.NotPredicates(p))
}
